#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import {
  deriveAuthorityKinds,
  normalize,
  parseJsonFile,
  validateReceipt,
} from "./wp-communications-lib.mjs";

const PACKETS_DIR = path.join(".GOV", "task_packets");

function parseSingleField(text, label) {
  const re = new RegExp(`^\\s*-\\s*(?:\\*\\*)?${label}(?:\\*\\*)?\\s*:\\s*(.+)\\s*$`, "mi");
  const match = text.match(re);
  return match ? match[1].trim() : "";
}

function nullableValue(value) {
  const raw = String(value ?? "").trim();
  if (!raw || /^null$/i.test(raw) || /^none$/i.test(raw) || /^n\/a$/i.test(raw)) return null;
  return raw;
}

function loadPacketContext(wpId) {
  const packetPath = path.join(PACKETS_DIR, `${wpId}.md`);
  if (!fs.existsSync(packetPath)) {
    throw new Error(`Official packet not found: ${normalize(packetPath)}`);
  }
  const packetText = fs.readFileSync(packetPath, "utf8");
  const receiptsFile = parseSingleField(packetText, "WP_RECEIPTS_FILE");
  const runtimeStatusFile = parseSingleField(packetText, "WP_RUNTIME_STATUS_FILE");
  const threadFile = parseSingleField(packetText, "WP_THREAD_FILE");
  const branch = parseSingleField(packetText, "LOCAL_BRANCH") || null;
  const worktreeDir = parseSingleField(packetText, "LOCAL_WORKTREE_DIR") || null;

  if (!receiptsFile) {
    throw new Error(`${normalize(packetPath)} does not declare WP_RECEIPTS_FILE`);
  }
  if (!fs.existsSync(receiptsFile)) {
    throw new Error(`Receipts ledger missing on disk: ${normalize(receiptsFile)}`);
  }

  return {
    packetPath: normalize(packetPath),
    receiptsFile: normalize(receiptsFile),
    runtimeStatusFile: normalize(runtimeStatusFile),
    threadFile: normalize(threadFile),
    branch: branch ? normalize(branch) : null,
    worktreeDir: worktreeDir ? normalize(worktreeDir) : null,
  };
}

export function appendWpReceipt({
  wpId,
  actorRole,
  actorSession,
  receiptKind,
  summary,
  stateBefore = null,
  stateAfter = null,
  refs = [],
  branch = null,
  worktreeDir = null,
  timestamp = null,
} = {}) {
  const WP_ID = String(wpId || "").trim();
  if (!WP_ID || !/^WP-/.test(WP_ID)) {
    throw new Error("WP_ID is required");
  }

  const context = loadPacketContext(WP_ID);
  const runtimeStatus = context.runtimeStatusFile && fs.existsSync(context.runtimeStatusFile)
    ? parseJsonFile(context.runtimeStatusFile)
    : null;
  const { authorityKind, validatorRoleKind } = deriveAuthorityKinds({
    actorRole,
    actorSession,
    runtimeStatus,
  });
  const entry = {
    schema_version: "wp_receipt@1",
    timestamp_utc: String(timestamp || new Date().toISOString()),
    wp_id: WP_ID,
    actor_role: String(actorRole || "").trim().toUpperCase(),
    actor_session: String(actorSession || "").trim(),
    actor_authority_kind: authorityKind,
    validator_role_kind: validatorRoleKind,
    receipt_kind: String(receiptKind || "").trim().toUpperCase(),
    summary: String(summary || "").trim(),
    branch: branch === undefined ? context.branch : nullableValue(branch),
    worktree_dir: worktreeDir === undefined ? context.worktreeDir : nullableValue(worktreeDir),
    state_before: nullableValue(stateBefore),
    state_after: nullableValue(stateAfter),
    refs: [context.packetPath, ...refs.filter(Boolean).map((value) => normalize(value))],
  };

  if (context.runtimeStatusFile && !entry.refs.includes(context.runtimeStatusFile)) entry.refs.push(context.runtimeStatusFile);
  if (context.threadFile && !entry.refs.includes(context.threadFile)) entry.refs.push(context.threadFile);
  if (!entry.refs.includes(context.receiptsFile)) entry.refs.push(context.receiptsFile);

  const errors = validateReceipt(entry);
  if (errors.length > 0) {
    throw new Error(`Receipt validation failed: ${errors.join("; ")}`);
  }

  fs.appendFileSync(context.receiptsFile, `${JSON.stringify(entry)}\n`, "utf8");
  return { context, entry };
}

function runCli() {
  const [wpId, actorRole, actorSession, receiptKind, summary, stateBefore, stateAfter] = process.argv.slice(2);
  if (!wpId || !actorRole || !actorSession || !receiptKind || !summary) {
    console.error("Usage: node .GOV/scripts/wp-receipt-append.mjs WP-{ID} <ACTOR_ROLE> <ACTOR_SESSION> <RECEIPT_KIND> \"<SUMMARY>\" [STATE_BEFORE] [STATE_AFTER]");
    process.exit(1);
  }

  const { context, entry } = appendWpReceipt({
    wpId,
    actorRole,
    actorSession,
    receiptKind,
    summary,
    stateBefore,
    stateAfter,
  });

  console.log(`[WP_RECEIPT] appended ${entry.receipt_kind} for ${entry.wp_id}`);
  console.log(`- ledger: ${context.receiptsFile}`);
  console.log(`- timestamp_utc: ${entry.timestamp_utc}`);
}

if (process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  runCli();
}

#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import {
  addMinutes,
  deriveAuthorityKinds,
  normalize,
  parseJsonFile,
  validateRuntimeStatus,
  RUNTIME_STATUS_VALUES,
  NEXT_ACTOR_VALUES,
  VALIDATOR_TRIGGER_VALUES,
  ACTIVE_ROLE_VALUES,
} from "./wp-communications-lib.mjs";
import { appendWpReceipt } from "./wp-receipt-append.mjs";

const PACKETS_DIR = path.join(".GOV", "task_packets");

function parseSingleField(text, label) {
  const re = new RegExp(`^\\s*-\\s*(?:\\*\\*)?${label}(?:\\*\\*)?\\s*:\\s*(.+)\\s*$`, "mi");
  const match = text.match(re);
  return match ? match[1].trim() : "";
}

function parsePacketStatus(text) {
  return (
    (text.match(/^\s*-\s*\*\*Status:\*\*\s*(.+)\s*$/mi) || [])[1] ||
    (text.match(/^\s*\*\*Status:\*\*\s*(.+)\s*$/mi) || [])[1] ||
    ""
  ).trim() || "Ready for Dev";
}

function parseIntegerField(text, label, fallback) {
  const raw = parseSingleField(text, label);
  if (!raw) return fallback;
  const parsed = Number.parseInt(raw, 10);
  return Number.isInteger(parsed) ? parsed : fallback;
}

function requirePacketContext(wpId) {
  const packetPath = path.join(PACKETS_DIR, `${wpId}.md`);
  if (!fs.existsSync(packetPath)) {
    throw new Error(`Official packet not found: ${normalize(packetPath)}`);
  }
  const packetText = fs.readFileSync(packetPath, "utf8");
  const runtimeStatusFile = parseSingleField(packetText, "WP_RUNTIME_STATUS_FILE");
  const receiptsFile = parseSingleField(packetText, "WP_RECEIPTS_FILE");
  if (!runtimeStatusFile) {
    throw new Error(`${normalize(packetPath)} does not declare WP_RUNTIME_STATUS_FILE`);
  }
  if (!receiptsFile) {
    throw new Error(`${normalize(packetPath)} does not declare WP_RECEIPTS_FILE`);
  }
  if (!fs.existsSync(runtimeStatusFile)) {
    throw new Error(`Runtime status file missing on disk: ${normalize(runtimeStatusFile)}`);
  }
  return {
    packetPath: normalize(packetPath),
    packetText,
    runtimeStatusFile: normalize(runtimeStatusFile),
    heartbeatIntervalMinutes: parseIntegerField(packetText, "HEARTBEAT_INTERVAL_MINUTES", 15),
    staleAfterMinutes: parseIntegerField(packetText, "STALE_AFTER_MINUTES", 45),
  };
}

function sessionStateForRuntimeStatus(runtimeStatus) {
  switch (runtimeStatus) {
    case "working":
      return "working";
    case "input_required":
      return "waiting";
    case "failed":
      return "blocked";
    case "completed":
    case "canceled":
      return "completed";
    default:
      return "idle";
  }
}

export function recordWpHeartbeat({
  wpId,
  actorRole,
  actorSession,
  currentPhase,
  runtimeStatus,
  nextExpectedActor,
  waitingOn,
  validatorTrigger = "NONE",
  lastEvent = null,
  worktreeDir = null,
} = {}) {
  const WP_ID = String(wpId || "").trim();
  const ACTOR_ROLE = String(actorRole || "").trim().toUpperCase();
  const ACTOR_SESSION = String(actorSession || "").trim();
  const CURRENT_PHASE = String(currentPhase || "").trim().toUpperCase();
  const RUNTIME_STATUS = String(runtimeStatus || "").trim();
  const NEXT_EXPECTED_ACTOR = String(nextExpectedActor || "").trim().toUpperCase();
  const WAITING_ON = String(waitingOn || "").trim();
  const VALIDATOR_TRIGGER = String(validatorTrigger || "NONE").trim().toUpperCase();
  const now = new Date().toISOString();

  if (!WP_ID || !/^WP-/.test(WP_ID)) throw new Error("WP_ID is required");
  if (!ACTIVE_ROLE_VALUES.includes(ACTOR_ROLE)) throw new Error(`Invalid ACTOR_ROLE: ${ACTOR_ROLE}`);
  if (!ACTOR_SESSION) throw new Error("ACTOR_SESSION is required");
  if (!CURRENT_PHASE || !/^[A-Z][A-Z0-9_]*$/.test(CURRENT_PHASE)) throw new Error(`Invalid CURRENT_PHASE: ${CURRENT_PHASE}`);
  if (!RUNTIME_STATUS_VALUES.includes(RUNTIME_STATUS)) throw new Error(`Invalid RUNTIME_STATUS: ${RUNTIME_STATUS}`);
  if (!NEXT_ACTOR_VALUES.includes(NEXT_EXPECTED_ACTOR)) throw new Error(`Invalid NEXT_EXPECTED_ACTOR: ${NEXT_EXPECTED_ACTOR}`);
  if (!WAITING_ON) throw new Error("WAITING_ON is required");
  if (!VALIDATOR_TRIGGER_VALUES.includes(VALIDATOR_TRIGGER)) throw new Error(`Invalid VALIDATOR_TRIGGER: ${VALIDATOR_TRIGGER}`);

  const context = requirePacketContext(WP_ID);
  const runtimeStatusPath = context.runtimeStatusFile;
  const runtime = parseJsonFile(runtimeStatusPath);
  const stateBefore = `${runtime.runtime_status}/${runtime.current_phase}`;
  const { authorityKind, validatorRoleKind } = deriveAuthorityKinds({
    actorRole: ACTOR_ROLE,
    actorSession: ACTOR_SESSION,
    runtimeStatus: runtime,
  });

  runtime.current_packet_status = parsePacketStatus(context.packetText);
  runtime.runtime_status = RUNTIME_STATUS;
  runtime.current_phase = CURRENT_PHASE;
  runtime.next_expected_actor = NEXT_EXPECTED_ACTOR;
  runtime.waiting_on = WAITING_ON;
  runtime.validator_trigger = VALIDATOR_TRIGGER;
  runtime.validator_trigger_reason = VALIDATOR_TRIGGER === "NONE" ? null : `${ACTOR_ROLE} signaled ${VALIDATOR_TRIGGER}`;
  runtime.ready_for_validation = ["READY_FOR_VALIDATION", "POST_WORK_PASS", "HANDOFF_READY"].includes(VALIDATOR_TRIGGER);
  runtime.ready_for_validation_reason = runtime.ready_for_validation ? runtime.validator_trigger_reason : null;
  runtime.last_event = String(lastEvent || `heartbeat_${ACTOR_ROLE.toLowerCase()}`);
  runtime.last_event_at = now;
  runtime.last_heartbeat_at = now;
  runtime.heartbeat_due_at = addMinutes(now, context.heartbeatIntervalMinutes);
  runtime.stale_after = addMinutes(now, context.staleAfterMinutes);

  const nextSessionState = sessionStateForRuntimeStatus(RUNTIME_STATUS);
  const filteredSessions = Array.isArray(runtime.active_role_sessions)
    ? runtime.active_role_sessions.filter((entry) => entry.role !== ACTOR_ROLE || entry.session_id !== ACTOR_SESSION)
    : [];
  filteredSessions.push({
    role: ACTOR_ROLE,
    session_id: ACTOR_SESSION,
    authority_kind: authorityKind,
    validator_role_kind: validatorRoleKind,
    worktree_dir: String(worktreeDir || context.packetText?.match?.(/^\s*-\s*LOCAL_WORKTREE_DIR\s*:\s*(.+)$/mi)?.[1] || runtime.current_worktree_dir || "<pending>").trim(),
    state: nextSessionState,
    last_heartbeat_at: now,
  });
  runtime.active_role_sessions = filteredSessions;

  const runtimeErrors = validateRuntimeStatus(runtime);
  if (runtimeErrors.length > 0) {
    throw new Error(`Runtime status validation failed: ${runtimeErrors.join("; ")}`);
  }

  fs.writeFileSync(runtimeStatusPath, `${JSON.stringify(runtime, null, 2)}\n`, "utf8");

  const summary = `${ACTOR_ROLE} heartbeat: ${RUNTIME_STATUS}/${CURRENT_PHASE}; next=${NEXT_EXPECTED_ACTOR}; waiting_on=${WAITING_ON}; validator_trigger=${VALIDATOR_TRIGGER}`;
  appendWpReceipt({
    wpId: WP_ID,
    actorRole: ACTOR_ROLE,
    actorSession: ACTOR_SESSION,
    receiptKind: "HEARTBEAT",
    summary,
    stateBefore,
    stateAfter: `${runtime.runtime_status}/${runtime.current_phase}`,
    refs: [runtimeStatusPath],
    worktreeDir: worktreeDir || runtime.current_worktree_dir || null,
  });

  return { runtimeStatusPath, runtime, summary };
}

function runCli() {
  const [wpId, actorRole, actorSession, currentPhase, runtimeStatus, nextExpectedActor, waitingOn, validatorTrigger, lastEvent, worktreeDir] =
    process.argv.slice(2);

  if (!wpId || !actorRole || !actorSession || !currentPhase || !runtimeStatus || !nextExpectedActor || !waitingOn) {
    console.error(
      "Usage: node .GOV/scripts/wp-heartbeat.mjs WP-{ID} <ACTOR_ROLE> <ACTOR_SESSION> <CURRENT_PHASE> <RUNTIME_STATUS> <NEXT_EXPECTED_ACTOR> <WAITING_ON> [VALIDATOR_TRIGGER] [LAST_EVENT] [WORKTREE_DIR]"
    );
    process.exit(1);
  }

  const result = recordWpHeartbeat({
    wpId,
    actorRole,
    actorSession,
    currentPhase,
    runtimeStatus,
    nextExpectedActor,
      waitingOn,
      validatorTrigger,
      lastEvent,
      worktreeDir,
    });

  console.log(`[WP_HEARTBEAT] updated ${wpId}`);
  console.log(`- runtime: ${result.runtimeStatusPath}`);
  console.log(`- summary: ${result.summary}`);
}

if (process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  runCli();
}

#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { normalize } from "./wp-communications-lib.mjs";
import { appendWpReceipt } from "./wp-receipt-append.mjs";

const PACKETS_DIR = path.join(".GOV", "task_packets");

function parseSingleField(text, label) {
  const re = new RegExp(`^\\s*-\\s*(?:\\*\\*)?${label}(?:\\*\\*)?\\s*:\\s*(.+)\\s*$`, "mi");
  const match = text.match(re);
  return match ? match[1].trim() : "";
}

function normalizeMultilineMessage(message) {
  return String(message || "")
    .replace(/\r\n/g, "\n")
    .split("\n")
    .map((line) => line.trimEnd())
    .filter((line, index, all) => !(index === 0 && line.trim() === "") && !(index === all.length - 1 && line.trim() === ""));
}

function loadThreadContext(wpId) {
  const packetPath = path.join(PACKETS_DIR, `${wpId}.md`);
  if (!fs.existsSync(packetPath)) {
    throw new Error(`Official packet not found: ${normalize(packetPath)}`);
  }
  const packetText = fs.readFileSync(packetPath, "utf8");
  const threadFile = parseSingleField(packetText, "WP_THREAD_FILE");
  if (!threadFile) {
    throw new Error(`${normalize(packetPath)} does not declare WP_THREAD_FILE`);
  }
  if (!fs.existsSync(threadFile)) {
    throw new Error(`Thread file missing on disk: ${normalize(threadFile)}`);
  }
  return { packetPath: normalize(packetPath), threadFile: normalize(threadFile) };
}

export function appendWpThreadEntry({ wpId, actorRole, actorSession, message, target = "", recordReceipt = true } = {}) {
  const WP_ID = String(wpId || "").trim();
  const ACTOR_ROLE = String(actorRole || "").trim().toUpperCase();
  const ACTOR_SESSION = String(actorSession || "").trim();
  const TARGET = String(target || "").trim();
  const bodyLines = normalizeMultilineMessage(message);

  if (!WP_ID || !/^WP-/.test(WP_ID)) throw new Error("WP_ID is required");
  if (!ACTOR_ROLE) throw new Error("ACTOR_ROLE is required");
  if (!ACTOR_SESSION) throw new Error("ACTOR_SESSION is required");
  if (bodyLines.length === 0 || !bodyLines.some((line) => line.trim().length > 0)) {
    throw new Error("message is required");
  }

  const context = loadThreadContext(WP_ID);
  const timestamp = new Date().toISOString();
  const header = [`- ${timestamp}`, ACTOR_ROLE, `session=${ACTOR_SESSION}`];
  if (TARGET) header.push(`target=${TARGET}`);
  const entryLines = [header.join(" | "), ...bodyLines.map((line) => `  ${line}`), ""];
  fs.appendFileSync(context.threadFile, `${entryLines.join("\n")}\n`, "utf8");

  if (recordReceipt) {
    appendWpReceipt({
      wpId: WP_ID,
      actorRole: ACTOR_ROLE,
      actorSession: ACTOR_SESSION,
      receiptKind: "THREAD_MESSAGE",
      summary: `${ACTOR_ROLE} -> ${TARGET || "thread"}: ${bodyLines[0]}`,
      refs: [context.threadFile],
      timestamp,
    });
  }

  return {
    threadFile: context.threadFile,
    timestamp,
    summary: `${ACTOR_ROLE} -> ${TARGET || "thread"}: ${bodyLines[0]}`,
    receiptAppended: recordReceipt,
  };
}

function runCli() {
  const [wpId, actorRole, actorSession, message, target] = process.argv.slice(2);
  if (!wpId || !actorRole || !actorSession || !message) {
    console.error("Usage: node .GOV/scripts/wp-thread-append.mjs WP-{ID} <ACTOR_ROLE> <ACTOR_SESSION> \"<message>\" [target]");
    process.exit(1);
  }

  const result = appendWpThreadEntry({ wpId, actorRole, actorSession, message, target });
  console.log(`[WP_THREAD] appended message for ${wpId}`);
  console.log(`- thread: ${result.threadFile}`);
  console.log(`- timestamp_utc: ${result.timestamp}`);
  console.log(`- summary: ${result.summary}`);
  console.log(`- receipt_appended: ${result.receiptAppended ? 'YES' : 'NO'}`);
}

if (process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  runCli();
}

import path from "node:path";
import { EXECUTION_OWNER_VALUES } from "./session-policy.mjs";

export const COMM_ROOT = ".GOV/roles_shared/WP_COMMUNICATIONS";
export const THREAD_FILE_NAME = "THREAD.md";
export const RUNTIME_STATUS_FILE_NAME = "RUNTIME_STATUS.json";
